const item = $input.first().json;
const data = item.data;
// data viene de Load Project Data ($json.data)
if (!data) {
  return [{ json: { valid: false, error: 'project_id no encontrado' } }];
}
if (!data.property_area_m2 || data.property_area_m2 <= 0) {
  return [{ json: { valid: false, error: 'property_area_m2 obligatorio (>0) para estimar demanda energetica' } }];
}
if (!data.location_province) {
  return [{ json: { valid: false, error: 'location_province obligatorio para zona climatica' } }];
}
return [{ json: { valid: true, ...data } }];

const promptRow = $input.first().json;
const project   = $('Validate Data').first().json;

const materialSummary = (project.materials || []).map(m => `- [${m.category}] ${m.name}${m.specification ? ' (' + m.specification + ')' : ''}: ${m.quantity || '?'} ${m.unit || ''}${m.room ? ' en ' + m.room : ''}`).join('\n') || '(sin materiales declarados)';

const design = project.design_option || {};
const briefing = project.briefing || {};

const prompt_user = `Proyecto: ${project.project_name}
Tipo: ${project.project_type} (${project.property_type})
Ubicacion: ${project.location_address || ''}, ${project.location_city || ''} (${project.location_province})
Superficie: ${project.property_area_m2} m2 utiles
Budget: ${project.budget_target || '?'} EUR

DESIGN OPTION SELECCIONADA:
Titulo: ${design.title || '(no seleccionada)'}
Descripcion: ${design.description || '-'}
Logica intervencion: ${design.intervention_logic || '-'}
Notas tecnicas: ${design.technical_notes || '-'}

BRIEFING:
Resumen: ${briefing.summary || '-'}
Objetivos: ${JSON.stringify(briefing.objectives || [])}
Constraints: ${JSON.stringify(briefing.constraints || [])}
Rooms_affected: ${JSON.stringify(briefing.rooms_affected || [])}

MATERIALES APROBADOS:
${materialSummary}

METADATA:
${JSON.stringify(project.metadata || {}, null, 2)}

---
Genera tu evaluacion energetica en JSON segun el schema. Responde SOLO el JSON, sin texto adicional.`;

return [{ json: {
  agent_name:   'agent_energy_assessor',
  prompt_system: promptRow.content,
  prompt_user:  prompt_user,
  model:        promptRow.model_recommended || 'gpt-4o',
  temperature:  promptRow.temperature !== null ? Number(promptRow.temperature) : 0.2,
  project_id:   project.project_id,
  next_version: project.next_version
}}];

const llm = $input.first().json;
let text = llm.text || llm.content || llm.response_text || '';
// strip markdown code blocks if any
text = text.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  // fallback: try to extract first JSON object
  const m = text.match(/\{[\s\S]*\}/);
  if (m) {
    try { parsed = JSON.parse(m[0]); } catch (_) {}
  }
}
if (!parsed) {
  parsed = {
    zona_climatica: null,
    demanda_calefaccion_kwh_m2_anyo: null,
    demanda_refrigeracion_kwh_m2_anyo: null,
    demanda_total_kwh_m2_anyo: null,
    transmitancia_envolvente_global: null,
    consumo_energia_primaria_kwh_m2_anyo: null,
    emisiones_co2_kg_m2_anyo: null,
    calificacion_demanda: null,
    calificacion_emisiones: null,
    cumple_he0: null,
    cumple_he1: null,
    analysis_summary: 'LLM no devolvio JSON valido. Revisar manualmente. Texto recibido: ' + text.substring(0, 200),
    recomendaciones: [],
    warnings: ['parse_failure']
  };
}
// Coerce types
const num = (v) => v === null || v === undefined || v === '' ? null : Number(v);
const out = {
  zona_climatica: parsed.zona_climatica || null,
  demanda_calefaccion_kwh_m2_anyo: num(parsed.demanda_calefaccion_kwh_m2_anyo),
  demanda_refrigeracion_kwh_m2_anyo: num(parsed.demanda_refrigeracion_kwh_m2_anyo),
  demanda_total_kwh_m2_anyo: num(parsed.demanda_total_kwh_m2_anyo),
  transmitancia_envolvente_global: num(parsed.transmitancia_envolvente_global),
  consumo_energia_primaria_kwh_m2_anyo: num(parsed.consumo_energia_primaria_kwh_m2_anyo),
  emisiones_co2_kg_m2_anyo: num(parsed.emisiones_co2_kg_m2_anyo),
  calificacion_demanda: parsed.calificacion_demanda || null,
  calificacion_emisiones: parsed.calificacion_emisiones || null,
  cumple_he0: typeof parsed.cumple_he0 === 'boolean' ? parsed.cumple_he0 : null,
  cumple_he1: typeof parsed.cumple_he1 === 'boolean' ? parsed.cumple_he1 : null,
  analysis_summary: parsed.analysis_summary || '',
  recomendaciones: Array.isArray(parsed.recomendaciones) ? parsed.recomendaciones : [],
  warnings: Array.isArray(parsed.warnings) ? parsed.warnings : [],
  llm_model: llm.model || 'gpt-4o',
  llm_tokens_in: llm.tokens_in || llm.usage?.prompt_tokens || null,
  llm_tokens_out: llm.tokens_out || llm.usage?.completion_tokens || null,
  llm_cost_usd: llm.cost_usd || null
};
return [{ json: out }];

// Tabla embebida de huella de carbono CO2eq por unidad funcional. Fuente aproximada ITeC BEDEC.
// Categorias coinciden con materials.category mas tipicas.
const CO2_FACTORS = {
  // categoria  -> kg CO2eq / unit
  'pavimento':       { porcelanico_m2: 18, ceramico_m2: 12, parquet_m2: 5, vinilico_m2: 8, microcemento_m2: 14 },
  'sanitarios':      { lavabo: 35, inodoro: 45, ducha: 50, banera: 90, bidet: 30 },
  'griferia':        { monomando: 15, termostatico: 25 },
  'cocina':          { mueble_ml: 60, encimera_ml: 80, electrodomestico: 200 },
  'carpinteria_int': { puerta_ud: 35, armario_ml: 70 },
  'carpinteria_ext': { ventana_pvc_m2: 80, ventana_aluminio_m2: 130, ventana_madera_m2: 60 },
  'pintura':         { plastica_m2: 1.2, esmalte_m2: 2.5 },
  'aislamiento':     { lana_mineral_m2: 5, eps_m2: 7, xps_m2: 10, sate_m2: 25 },
  'instalacion_electrica': { punto_luz: 8, toma_corriente: 6, cuadro: 50 },
  'instalacion_fontaneria': { metro_per: 1.5, llave_corte: 3, calentador: 120 },
  'climatizacion':   { split_ud: 250, suelo_radiante_m2: 25, radiador: 80 }
};

const project = $('Validate Data').first().json;
const llmOut  = $input.first().json;

const breakdown = {};
let totalKg = 0;

(project.materials || []).forEach(m => {
  const cat = (m.category || '').toLowerCase();
  const qty = Number(m.quantity) || 0;
  if (!cat || qty <= 0) return;
  // Heuristica: buscar mejor match por nombre/spec en CO2_FACTORS
  const catFactors = CO2_FACTORS[cat];
  if (!catFactors) return;
  // Tomar el primer factor de la categoria como aproximacion
  const firstKey = Object.keys(catFactors)[0];
  const factor = catFactors[firstKey] || 0;
  const kg = qty * factor;
  totalKg += kg;
  breakdown[cat] = (breakdown[cat] || 0) + kg;
});

return [{ json: {
  ...llmOut,
  huella_carbono_embebida_kg: Math.round(totalKg * 100) / 100,
  huella_carbono_breakdown: breakdown
}}];

const inserted = $input.first().json;
const raw      = $('Calculate Embedded Footprint').first().json;
const project  = $('Validate Data').first().json;

const CALI_COLOR = { A:'#1f8a3a', B:'#3aaa49', C:'#a8c037', D:'#fece00', E:'#f29826', F:'#e8602b', G:'#d11919' };
const calCol = (c) => CALI_COLOR[c] || '#888';
const recos = (raw.recomendaciones || []).map(r => `<li><b>[${r.prioridad || 'media'}]</b> ${r.descripcion}${r.impacto_kwh_m2_anyo ? ' — impacto ~' + r.impacto_kwh_m2_anyo + ' kWh/m2/año' : ''}</li>`).join('');
const warns = (raw.warnings || []).map(w => '<li>' + w + '</li>').join('');

const html = `<div style="font-family:Arial,sans-serif;max-width:680px;margin:0 auto">
<h2 style="color:#2c3e50">Evaluacion energetica generada</h2>
<h3 style="color:#7f8c8d">${project.project_name}</h3>
<table style="width:100%;border-collapse:collapse;margin:16px 0">
  <tr><td style="padding:6px;background:#f3f4f6"><b>Zona climatica</b></td><td style="padding:6px">${raw.zona_climatica || '?'}</td></tr>
  <tr><td style="padding:6px;background:#f3f4f6"><b>Demanda total</b></td><td style="padding:6px">${raw.demanda_total_kwh_m2_anyo || '?'} kWh/m² año (calef ${raw.demanda_calefaccion_kwh_m2_anyo || '?'} + refrig ${raw.demanda_refrigeracion_kwh_m2_anyo || '?'})</td></tr>
  <tr><td style="padding:6px;background:#f3f4f6"><b>U envolvente media</b></td><td style="padding:6px">${raw.transmitancia_envolvente_global || '?'} W/m²K</td></tr>
  <tr><td style="padding:6px;background:#f3f4f6"><b>Emisiones</b></td><td style="padding:6px">${raw.emisiones_co2_kg_m2_anyo || '?'} kg CO2/m² año</td></tr>
  <tr><td style="padding:6px;background:#f3f4f6"><b>Calificacion demanda</b></td><td style="padding:6px"><span style="background:${calCol(raw.calificacion_demanda)};color:white;padding:4px 10px;border-radius:4px;font-weight:bold">${raw.calificacion_demanda || '?'}</span></td></tr>
  <tr><td style="padding:6px;background:#f3f4f6"><b>Calificacion emisiones</b></td><td style="padding:6px"><span style="background:${calCol(raw.calificacion_emisiones)};color:white;padding:4px 10px;border-radius:4px;font-weight:bold">${raw.calificacion_emisiones || '?'}</span></td></tr>
  <tr><td style="padding:6px;background:#f3f4f6"><b>Cumple HE0/HE1</b></td><td style="padding:6px">${raw.cumple_he0 === null ? 'n/d' : (raw.cumple_he0 ? '✅' : '❌')} HE0 / ${raw.cumple_he1 === null ? 'n/d' : (raw.cumple_he1 ? '✅' : '❌')} HE1</td></tr>
  <tr><td style="padding:6px;background:#f3f4f6"><b>Huella embebida (materiales)</b></td><td style="padding:6px">${raw.huella_carbono_embebida_kg} kg CO2eq</td></tr>
</table>
<p><b>Analisis:</b> ${raw.analysis_summary || ''}</p>
${recos ? '<h3>Recomendaciones</h3><ul>' + recos + '</ul>' : ''}
${warns ? '<p style="background:#fff8e1;padding:10px;border-left:4px solid #fece00"><b>Avisos:</b><ul>' + warns + '</ul></p>' : ''}
<p style="font-size:11px;color:#95a5a6">Estimacion automatica (no es certificado oficial CEE). Asessment ID: ${inserted.id}, version ${inserted.version}.</p>
</div>`;
return [{ json: { html_body: html, project_name: project.project_name, calificacion_demanda: raw.calificacion_demanda || '?' } }];
